import React from "react";
import MessageForm from "./MessageForm";

const formatTime = (dateString) => new Date(dateString).toLocaleTimeString([], { hour: "2-digit", minute: "2-digit" });
const reactionChoices = [
  String.fromCodePoint(0x1F44D),
  String.fromCodePoint(0x2764, 0xFE0F),
  String.fromCodePoint(0x1F602),
  String.fromCodePoint(0x1F525),
  String.fromCodePoint(0x1F62E)
];

const API_URL = process.env.REACT_APP_API_URL || "";
const API_BASE = API_URL.replace(/\/api\/?$/, "");

const toAttachmentUrl = (url) => {
  if (!url) return "";
  if (url.startsWith("http://") || url.startsWith("https://")) return url;
  return `${API_BASE}${url}`;
};

const isImage = (mimeType = "") => mimeType.startsWith("image/");

export default function ChatInterface({
  activeRoom,
  messages,
  currentUser,
  onSendMessage,
  onToggleReaction,
  onLeaveRoom,
  onStartAudioCall,
  onStartVideoCall,
  onEndCall,
  callState,
  localVideoRef,
  remoteVideoRef
}) {
  if (!activeRoom) {
    return (
      <section className="chat-interface glass empty-chat">
        <h3>Select a room to start chatting</h3>
        <p>Join a room from the left panel or create a new one.</p>
      </section>
    );
  }

  const initials = activeRoom.name?.slice(0, 2).toUpperCase() || "RM";
  const memberCount = activeRoom.members?.length || 0;

  return (
    <section className="chat-interface glass">
      <header className="chat-head">
        <div className="chat-title-wrap">
          <div className="chat-avatar">{initials}</div>
          <div>
            <h3>{activeRoom.name}</h3>
            <p>{activeRoom.description || "chat"}</p>
          </div>
        </div>

        <div className="chat-head-actions">
          <span className="member-pill">
            <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" aria-hidden="true">
              <path d="M16 21v-2a4 4 0 0 0-4-4H5a4 4 0 0 0-4 4v2" />
              <circle cx="8.5" cy="7" r="4" />
              <path d="M20 8v6M23 11h-6" />
            </svg>
            {memberCount}
          </span>
          <button
            type="button"
            className="ghost-btn head-link-btn"
            onClick={() => onStartAudioCall(activeRoom._id)}
            disabled={callState?.connecting || callState?.inCall}
          >
            Call
          </button>
          <button
            type="button"
            className="ghost-btn head-link-btn"
            onClick={() => onStartVideoCall(activeRoom._id)}
            disabled={callState?.connecting || callState?.inCall}
          >
            Video
          </button>
          <button type="button" className="ghost-btn head-link-btn" onClick={() => onLeaveRoom(activeRoom._id)}>Leave</button>
          <button type="button" className="ghost-btn dots-btn" aria-label="More options">...</button>
        </div>
      </header>

      {callState?.incoming ? (
        <div className="call-banner">
          <span>{callState.incoming.fromName} is calling ({callState.incoming.callType === "video" ? "video" : "audio"})</span>
          <div className="call-banner-actions">
            <button type="button" className="primary-btn" onClick={callState.onAcceptIncoming}>Accept</button>
            <button type="button" className="danger-btn" onClick={callState.onRejectIncoming}>Reject</button>
          </div>
        </div>
      ) : null}

      {callState?.inCall || callState?.connecting ? (
        <div className="call-panel">
          <div className="call-status">
            {callState.connecting ? "Connecting call..." : `In ${callState.callType === "video" ? "video" : "audio"} call`}
          </div>
          {callState.callType === "video" ? (
            <div className="call-videos">
              <video ref={remoteVideoRef} autoPlay playsInline className="call-video remote" />
              <video ref={localVideoRef} autoPlay playsInline muted className="call-video local" />
            </div>
          ) : (
            <audio ref={remoteVideoRef} autoPlay />
          )}
          <button type="button" className="danger-btn" onClick={onEndCall}>End Call</button>
        </div>
      ) : null}

      <div className="message-list">
        {messages.map((message) => {
          const ownMessage = (message.user?._id || message.user?.id) === currentUser?.id;
          if (message.system) {
            return (
              <div className="system-message" key={message._id || message.createdAt + message.content}>
                <span>{message.content}</span>
                <small>{formatTime(message.createdAt)}</small>
              </div>
            );
          }

          return (
            <article key={message._id || message.createdAt + message.content} className={ownMessage ? "msg own" : "msg"}>
              <div className="msg-meta">
                <strong>{message.user?.username || "Unknown"}</strong>
                <small>{formatTime(message.createdAt)}</small>
              </div>

              {message.content ? <p>{message.content}</p> : null}

              {message.attachments?.length ? (
                <div className="msg-attachments">
                  {message.attachments.map((file) => (
                    <a key={`${file.url}-${file.fileName}`} href={toAttachmentUrl(file.url)} target="_blank" rel="noreferrer" className="msg-file-link">
                      {isImage(file.mimeType) ? <img src={toAttachmentUrl(file.url)} alt={file.fileName} className="msg-image" /> : null}
                      <span>{file.fileName}</span>
                    </a>
                  ))}
                </div>
              ) : null}

              <div className="reactions-row">
                {reactionChoices.map((emoji) => {
                  const reaction = message.reactions?.find((entry) => entry.emoji === emoji);
                  const count = reaction?.users?.length || 0;
                  const reacted = reaction?.users?.some((u) => (u.id || u._id) === currentUser?.id);
                  return (
                    <button key={emoji} type="button" className={reacted ? "reaction-btn active" : "reaction-btn"} onClick={() => onToggleReaction(message._id, emoji)}>
                      {emoji} {count || ""}
                    </button>
                  );
                })}
              </div>
            </article>
          );
        })}
      </div>

      <MessageForm onSend={onSendMessage} />
    </section>
  );
}
